            $(el).parent().find(".navigrid-extensions-enable, .navigrid-extensions-remove").css("opacity", 0.9);
            $(el).parent().find("img").css("opacity", 1);
            $(el).parent().attr("enabled", '0');
        }
        else
        {
            $(el).parent().parent().find("*").css("opacity", 1);
            $(el).parent().attr("enabled", '1');
        }
    });
}

