	if (plupload.typeOf(files) !== 'array') {
		files = [files];
	}

	$.each(files, function(i, file) {
		var ext = o.core.utils.Mime.getFileExtension(file.name) || 'none';

		html += file_html.replace(/\{(\w+)\}/g, function($0, $1) {
