				case 'thumb_width':
				case 'thumb_height':
					return self.options[$1];

				case 'size':
					return plupload.formatSize(file.size);

				case 'ext':
					return ext;

				default:
					return file[$1] || '';
			}
		});
	});

	self.filelist.append(html);
},


