/**
 * 复制到目录
* $dirsrc  原目录
* $dirto  目标目录
*
*/
private function copydir($dirsrc, $dirto) {
    //如果原来的文件存在， 是不是一个目录

    if(file_exists($dirto)) {
        if(!is_dir($dirto)) {
            echo "目标不是一个目录， 不能copy进去<br>";
            exit;   
        }
    }else{
        mkdir($dirto);
    }


    $dir = opendir($dirsrc);

    while($filename = readdir($dir)) {
        if($filename != "." && $filename !="..") {
            $srcfile = $dirsrc."/".$filename;  //原文件
            $tofile = $dirto."/".$filename;    //目标文件

            if(is_dir($srcfile)) {
                $this->copydir($srcfile, $tofile);  //递归处理所有子目录
            }else{
                copy($srcfile, $tofile);
            }

        }
    }
}

// 删除文件夹及文件夹下所有的文件
private function deldir($dir) {
    //先删除目录下的文件：
    $dh = opendir($dir);
    while ($file = readdir($dh)) {
        if($file != "." && $file!="..") {
        $fullpath = $dir."/".$file;
        if(!is_dir($fullpath)) {
            unlink($fullpath);
        } else {
            $this->deldir($fullpath);
        }
        }
    }
    closedir($dh);

    //删除当前文件夹：
    if(rmdir($dir)) {
        return true;
    } else {
        return false;
    }
}

